  ('social-worker-moex-01557', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '現代公共救助基礎可追溯至濟貧法案（Poor law），關於現代公共救助與濟貧法案關係，下列敘 述何者錯誤？', '["濟貧法案向教區地主抽濟貧稅的規定，是政府以稅收辦理救濟先例，政府擔負起無力供養自身 者的救濟義務", "濟貧法案規定有能力的貧民，必須工作換取救濟，開現代以工代賑先例", "濟貧法案明定親屬責任及以居住地為接受救濟條件，與今日公共救助對象的資格相去無多", "濟貧法案以院內救濟為原則，現代公共救助機構式與家庭式兼而有之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01558', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近代英國社會工作專業發展歷史中，1982年的那一份報告主張社會工作應朝向「社區社會工作」 （community social work）的方向發展，讓社會工作實務出現社區化、市場化發展？', '["貝弗里奇報告書", "巴克萊報告書", "韋伯報告書", "普勞頓報告書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01559', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者已服務了個案三年，被委託單位質疑其服務目標的達成度、效率與成本效益等問題。 這屬於「全球化」對社會工作專業化的何項影響？', '["掌握知識的不確定性", "本土價值與殖民價值的衝突", "專業關係建立與新公共管理主義的衝突", "風險社會的管控機制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01560', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '臺灣社會工作發展自戰後約可分為五個時期，請將下列社會工作發展重點排出先後順序：①中國', '["在高雄、花蓮、新竹、澎湖及屏東成立救濟院", "政府提出法案納編約聘社工員", "社會工作員制度法制化  ⑤成立社會工作師專業證照制度", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
